-- Connect to Redis with connection pooling
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown")
    end

    if REDIS_PASSWORD then
        local res, auth_err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Failed to authenticate with Redis: " .. (auth_err or "unknown")
        end
    end

    return red
end

-- Return Redis connection to the pool
local function release_redis_connection(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Validate plugin code for basic safety checks
local function validate_plugin_code(code)
    if not code or type(code) ~= "string" then
        return false, "Plugin code must be a non-empty string"
    end

    if #code > 65536 then
        return false, "Plugin code exceeds maximum size of 64KB"
    end

    -- Blocklist of dangerous patterns
    local dangerous_patterns = {
        { pattern = "os%s*%.%s*execute", desc = "os.execute" },
        { pattern = "os%s*%.%s*remove", desc = "os.remove" },
        { pattern = "os%s*%.%s*rename", desc = "os.rename" },
        { pattern = "os%s*%.%s*tmpname", desc = "os.tmpname" },
        { pattern = "io%s*%.", desc = "io library" },
        { pattern = "loadfile", desc = "loadfile" },
        { pattern = "dofile", desc = "dofile" },
        { pattern = "require%s*%(?%s*['\"]ffi", desc = "FFI access" },
        { pattern = "rawset%s*%(", desc = "rawset" },
        { pattern = "rawget%s*%(", desc = "rawget" },
        { pattern = "setmetatable", desc = "setmetatable" },
        { pattern = "getmetatable", desc = "getmetatable" },
        { pattern = "debug%s*%.", desc = "debug library" },
        { pattern = "package%s*%.", desc = "package library" },
        { pattern = "collectgarbage", desc = "collectgarbage" },
        { pattern = "setfenv", desc = "setfenv" },
        { pattern = "getfenv", desc = "getfenv" },
        { pattern = "coroutine%s*%.", desc = "coroutine library" },
        { pattern = "newproxy", desc = "newproxy" },
    }

    for _, check in ipairs(dangerous_patterns) do
        if string.find(code, check.pattern) then
            return false, "Plugin code contains forbidden construct: " .. check.desc
        end
    end

    return true
end

-- Compile and cache plugin code
local function compile_plugin(plugin_name, code)
    local valid, validation_err = validate_plugin_code(code)
    if not valid then
        return nil, validation_err
    end

    local chunk_name = "plugin:" .. (plugin_name or "anonymous")

    -- Use load() (Lua 5.1 uses loadstring)
    local load_fn = load or loadstring
    local func, compile_err = load_fn(code, chunk_name)
    if not func then
        return nil, "Failed to compile plugin '" .. chunk_name .. "': " .. (compile_err or "unknown")
    end

    return func
end

-- Execute a compiled plugin function within a sandbox
local function execute_plugin(func, plugin_name, ctx)
    local sandbox = create_sandbox_env(ctx)

    -- Set the environment for the plugin function
    if setfenv then
        -- Lua 5.1 / LuaJIT
        setfenv(func, sandbox)
    end

    -- Execute the plugin factory function to get the plugin table/function
    local ok, plugin_or_err = pcall(func)
    if not ok then
        return nil, "Plugin '" .. (plugin_name or "anonymous") .. "' initialization failed: " .. tostring(plugin_or_err)
    end

    return plugin_or_err
end

-- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    -- Check shared dict cache first
    if plugin_cache then
        local cached_code = plugin_cache:get("code:" .. plugin_name)
        if cached_code then
            ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
            return cached_code
        end
    end

    local red, err = get_redis_connection()
    if not red then
        return nil, err
    end

    -- Load plugin code
    local code, redis_err = red:get(REDIS_PLUGIN_PREFIX .. plugin_name)
    if not code or code == ngx.null then
        release_redis_connection(red)
        return nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Optionally load plugin metadata
    local meta_raw = red:get(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")
    local meta = nil
    if meta_raw and meta_raw ~= ngx.null then
        meta = cjson.decode(meta_raw)
    end

    release_redis_connection(red)

    -- Cache in shared dict
    if plugin_cache then
        plugin_cache:set("code:" .. plugin_name, code, PLUGIN_CACHE_TTL)
        if meta then
            plugin_cache:set("meta:" .. plugin_name, cjson.encode(meta), PLUGIN_CACHE_TTL)
        end
    end

    return code, nil, meta
end

-- Load plugin code from HTTP header
local function load_plugin_from_header(header_name)
    local headers = ngx.req.get_headers()
    local code = headers[header_name or "X-Gateway-Plugin-Code"]
    if not code then
        return nil, "No plugin code found in header"
    end

    -- Decode base64 if the content-encoding header indicates so
    local encoding = headers["X-Gateway-Plugin-Encoding"]
    if encoding and encoding:lower() == "base64" then
        local decoded = ngx.decode_base64(code)
        if not decoded then
            return nil, "Failed to decode base64 plugin code"
        end
        code = decoded
    end

    return code
end

-- Plugin chain executor - runs multiple plugins in sequence
local function execute_plugin_chain(plugin_names, phase, ctx)
    ctx = ctx or {}
    ctx._phase = phase or "access"
    ctx._chain_index = 0
    ctx._chain_aborted = false
    local results = {}

    for i, plugin_name in ipairs(plugin_names) do
        if ctx._chain_aborted then
            ngx.log(ngx.INFO, "Plugin chain aborted at index ", i - 1)
            break
        end

        ctx._chain_index = i

        local code, load_err = load_plugin_from_redis(plugin_name)
        if not code then
            ngx.log(ngx.ERR, "Failed to load plugin '", plugin_name, "': ", load_err)
            table.insert(results, {
                plugin = plugin_name,
                success = false,
                error = load_err,
            })
        else
            local func, compile_err = compile_plugin(plugin_name, code)
            if not func then
                ngx.log(ngx.ERR, "Failed to compile plugin '", plugin_name, "': ", compile_err)
                table.insert(results, {
                    plugin = plugin_name,
                    success = false,
                    error = compile_err,
                })
            else
                local plugin_obj, exec_err = execute_plugin(func, plugin_name, ctx)
                if not plugin_obj then
                    ngx.log(ngx.ERR, "Failed to execute plugin '", plugin_name, "': ", exec_err)
                    table.insert(results, {
                        plugin = plugin_name,
                        success = false,
                        error = exec_err,
                    })
                else
                    -- If plugin returns a table, call the appropriate phase handler
                    local phase_result
                    local phase_ok = true
                    local phase_err

                    if type(plugin_obj) == "table" and type(plugin_obj[phase]) == "function" then
                        phase_ok, phase_err = pcall(function()
                            phase_result = plugin_obj[phase](plugin_obj, ctx)
                        end)
                    elseif type(plugin_obj) == "function" then
                        phase_ok, phase_err = pcall(function()
                            phase_result = plugin_obj(ctx)
                        end)
                    elseif type(plugin_obj) == "table" and type(plugin_obj.handler) == "function" then
                        phase_ok, phase_err = pcall(function()
                            phase_result = plugin_obj.handler(ctx)
                        end)
                    else
                        -- Plugin returned a value (could be a result directly)
                        phase_result = plugin_obj
                    end

                    if not phase_ok then
                        ngx.log(ngx.ERR, "Plugin '", plugin_name, "' phase handler error: ", phase_err)
                        table.insert(results, {
                            plugin = plugin_name,
                            success = false,
                            error = tostring(phase_err),
                        })
                    else
                        table.insert(results, {
                            plugin = plugin_name,
                            success = true,
                            result = phase_result,
                        })
                    end
                end
            end
        end
    end

    return results
end

-- Register a plugin in Redis
local function register_plugin(plugin_name, code, metadata)
    local valid, validation_err = validate_plugin_code(code)
    if not valid then
        return false, validation_err
    end

    -- Verify it compiles
    local func, compile_err = compile_plugin(plugin_name, code)
    if not func then
        return false, compile_err
    end

    local red, err = get_redis_connection()
    if not red then
        return false, err
    end

    local ok, redis_err = red:set(REDIS_PLUGIN_PREFIX .. plugin_name, code)
    if not ok then
        release_redis_connection(red)
        return false, "Failed to store plugin in Redis: " .. (redis_err or "unknown")
    end

    -- Store metadata if provided
    if metadata then
        metadata.registered_at = ngx.now()
        metadata.name = plugin_name
        local meta_json = cjson.encode(metadata)
        red:set(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta", meta_json)
    end

    -- Add to plugin registry set
    red:sadd(REDIS_PLUGIN_PREFIX .. "_registry", plugin_name)

    release_redis_connection(red)

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
        plugin_cache:delete("meta:" .. plugin_name)
    end

    return true
end

-- Unregister a plugin from Redis
local function unregister_plugin(plugin_name)
    local red, err = get_redis_connection()
    if not red then
        return false, err
    end

    red:del(REDIS_PLUGIN_PREFIX .. plugin_name)
    red:del(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")
    red:srem(REDIS_PLUGIN_PREFIX .. "_registry", plugin_name)

    release_redis_connection(red)

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
        plugin_cache:delete("meta:" .. plugin_name)
    end

    return true
end

-- List all registered plugins
local function list_plugins()
    local red, err = get_redis_connection()
    if not red then
        return nil, err
    end

    local members, redis_err = red:smembers(REDIS_PLUGIN_PREFIX .. "_registry")
    if not members then
        release_redis_connection(red)
        return nil, "Failed to list plugins: " .. (redis_err or "unknown")
    end

    local plugins = {}
    for _, name in ipairs(members) do
        local meta_raw = red:get(REDIS_PLUGIN_PREFIX .. name .. ":meta")
        local meta = nil
        if meta_raw and meta_raw ~= ngx.null then
            meta = cjson.decode(meta_raw)
        end
        table.insert(plugins, {
            name = name,
            metadata = meta,
        })
    end

    release_redis_connection(red)
    return plugins
end

-- Flush plugin cache
local function flush_cache(plugin_name)
    if not plugin_cache then
        return true
    end

    if plugin_name then
        plugin_cache:delete("code:" .. plugin_name)
        plugin_cache:delete("meta:" .. plugin_name)
    else
        plugin_cache:flush_all()
        plugin_cache:flush_expired()
    end

    return true
end

