        if not func then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = compile_err }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local ctx = payload.context or {}
        local plugin_obj, exec_err = execute_plugin(func, payload.name or "inline", ctx)
        if not plugin_obj and exec_err then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = exec_err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({
            success = true,
            result = plugin_obj,
            context = ctx,
