        end

        local meta_raw
        if plugin_cache then
            meta_raw = plugin_cache:get("meta:" .. plugin_name)
        end
        local meta = nil
        if meta_raw then
            meta = cjson.decode(meta_raw)
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({
            success = true,
            name = plugin_name,
            code = code,
            metadata = meta,
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- POST /plugins/cache/flush - Flush the plugin cache
    if uri == "/plugins/cache/flush" and method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        local plugin_name = nil
        if body then
            local payload = cjson.decode(body)
            if payload then
                plugin_name = payload.name
            end
        end

        flush_cache(plugin_name)

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({
            success = true,
            message = plugin_name and ("Cache flushed for plugin '" .. plugin_name .. "'") or "All plugin caches flushed",
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- Default: Not found
    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say(cjson.encode({
        error = "Endpoint not found",
        available_endpoints = {
            "GET    /plugins                     - List all plugins",
            "GET    /plugins/{name}              - Get plugin details",
            "POST   /plugins/register            - Register a plugin",
            "DELETE /plugins/{name}              - Unregister a plugin",
            "POST   /plugins/execute/{name}      - Execute a registered plugin",
            "POST   /plugins/execute-inline      - Execute inline plugin code",
            "POST   /plugins/execute-header      - Execute plugin from HTTP header",
            "POST   /plugins/execute-chain       - Execute a chain of plugins",
            "POST   /plugins/cache/flush         - Flush plugin cache",
        },
    }))
    return ngx.exit(ngx.HTTP_NOT_FOUND)
end

-- ============================================================
-- Access phase handler - Runs configured plugins for each request
-- ============================================================
local function access_phase_handler()
    -- Check for route-specific plugin configuration
    local route_plugins_header = ngx.req.get_headers()["X-Gateway-Plugins"]
    if not route_plugins_header then
        return
    end

    -- Parse comma-separated plugin names
    local plugin_names = {}
    for name in string.gmatch(route_plugins_header, "([^,]+)") do
        name = name:match("^%s*(.-)%s*$") -- trim whitespace
        if name ~= "" then
            table.insert(plugin_names, name)
        end
    end

    if #plugin_names == 0 then
        return
    end

    local ctx = ngx.ctx.plugin_ctx or {}
    ngx.ctx.plugin_ctx = ctx

    local results = execute_plugin_chain(plugin_names, "access", ctx)

    -- Check for any failures that should block the request
    for _, result in ipairs(results) do
        if not result.success then
            ngx.log(ngx.ERR, "Plugin '", result.plugin, "' failed: ", result.error)
        end
        if result.result and type(result.result) == "table" and result.result.block then
            ngx.status = result.result.status or ngx.HTTP_FORBIDDEN
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({
                error = result.result.message or "Request blocked by plugin",
                plugin = result.plugin,
            }))
            return ngx.exit(ngx.status)
        end
    end
end

