    unregister_plugin = unregister_plugin,
    list_plugins = list_plugins,

    -- HTTP header loading
    load_plugin_from_header = load_plugin_from_header,

    -- Plugin chain execution
    execute_plugin_chain = execute_plugin_chain,

    -- Cache management
    flush_cache = flush_cache,

    -- HTTP handlers
    handle_api_request = handle_api_request,
    access_phase_handler = access_phase_handler,
}

return _M